final:
module jk_flip_flop (
    input clk,
    input j,
    input k,
    output reg q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (j && !k)
        q <= 1;
    else if (!j && k)
        q <= 0;
    else if (j && k)
        q <= ~q;
end

endmodule
